def decode_id_token_unverified(id_token):
    """
    Decode the payload of a JWT id_token without cryptographic verification.
    NOTE: In production, you MUST verify the signature using the IdP's JWKS.
    Consider using PyJWT or python-jose for full verification.
    """
    try:
        parts = id_token.split(".")
        if len(parts) != 3:
            return None

        payload_b64 = parts[1]
        # Add padding if necessary
        padding = 4 - len(payload_b64) % 4
        if padding != 4:
            payload_b64 += "=" * padding

        payload_json = base64.urlsafe_b64decode(payload_b64)
        return json.loads(payload_json)
    except Exception:
        return None


def validate_id_token_claims(claims):
    """
    Validate essential claims in the id_token.
    In production, also verify:
    - Signature against JWKS
    - exp (expiration)
    - iat (issued at)
    - aud matches client_id
    - iss matches expected issuer
    """
    if not claims:
        return False, "Failed to decode id_token"

    # Verify issuer
    if claims.get("iss") != OIDC_CONFIG["issuer"]:
        return False, f"Invalid issuer: {claims.get('iss')}"

    # Verify audience
    aud = claims.get("aud")
    if isinstance(aud, list):
        if OIDC_CONFIG["client_id"] not in aud:
            return False, "Client ID not in audience"
    elif aud != OIDC_CONFIG["client_id"]:
        return False, f"Invalid audience: {aud}"

    # Verify nonce — THIS IS THE CRITICAL SECURITY CHECK
    # Without this, tokens can be replayed by attackers
    expected_nonce = session.get("oidc_nonce")
    if not expected_nonce:
        return False, "No nonce found in session"
    if claims.get("nonce") != expected_nonce:
        return False, "Nonce mismatch — possible replay attack"

    import time
    exp = claims.get("exp")
    if exp and time.time() > exp:
        return False, "Token has expired"

    return True, "Valid"


def login_required(f):
    """Decorator to require authentication for routes."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if "user" not in session:
            session["next_url"] = request.url
            return redirect(url_for("login"))
        return f(*args, **kwargs)
    return decorated_function


