@app.route("/login")
def login():
    """Initiate OIDC authentication flow."""
    # Generate state parameter to prevent CSRF
    state = secrets.token_urlsafe(32)
    session["oidc_state"] = state

    # Generate nonce to prevent token replay attacks
    # This is REQUIRED for implicit flow (response_type=id_token)
    # per the OpenID Connect Core spec section 3.2.2.1
    nonce = secrets.token_urlsafe(32)
    session["oidc_nonce"] = nonce

    # Build authorization URL
    auth_params = {
        "client_id": OIDC_CONFIG["client_id"],
        "redirect_uri": OIDC_CONFIG["redirect_uri"],
        "scope": OIDC_CONFIG["scope"],
        "response_type": OIDC_CONFIG["response_type"],
        "state": state,
        "nonce": nonce,  # Critical for security — prevents replay attacks
        "response_mode": "fragment",
    }

    auth_url = OIDC_CONFIG["authorization_endpoint"] + "?" + "&".join(
        f"{key}={requests.utils.quote(str(value))}"
        for key, value in auth_params.items()
    )

    return redirect(auth_url)


@app.route("/callback")
def callback():
    """
    Handle the OIDC callback.

    For response_type=id_token, the token is returned in the URL fragment
    (after #), which is not sent to the server by the browser. We need a
    small JavaScript page to extract it and POST it to our server.

    If using response_mode=form_post, the IdP will POST the token directly.
    """
    # Check if this is a form_post callback (id_token in POST body)
    id_token = request.form.get("id_token") or request.args.get("id_token")

    if id_token:
        return _process_id_token(id_token)

    # For fragment-based responses, serve a page that extracts the fragment
    # and sends it to the server
    return """
    <html>
    <head><title>Processing login...</title></head>
    <body>
        <p>Processing your login, please wait...</p>
        <script>
            // The id_token is in the URL fragment (after #)
            var fragment = window.location.hash.substring(1);
            var params = new URLSearchParams(fragment);
            var idToken = params.get('id_token');
            var state = params.get('state');

            if (idToken) {
                // POST the token to the server for validation
                var form = document.createElement('form');
                form.method = 'POST';
                form.action = '/callback/process';

                var tokenInput = document.createElement('input');
                tokenInput.type = 'hidden';
                tokenInput.name = 'id_token';
                tokenInput.value = idToken;
                form.appendChild(tokenInput);

                var stateInput = document.createElement('input');
                stateInput.type = 'hidden';
                stateInput.name = 'state';
                stateInput.value = state;
                form.appendChild(stateInput);

                document.body.appendChild(form);
                form.submit();
            } else {
                document.body.innerHTML = '<p>Error: No id_token received. '
                    + '<a href="/login">Try again</a></p>';
            }
        </script>
    </body>
    </html>
    """


@app.route("/callback/process", methods=["POST"])
def callback_process():
    """Process the id_token submitted from the fragment extraction page."""
    id_token = request.form.get("id_token")
    state = request.form.get("state")

    if not id_token:
        abort(400, "No id_token provided")

    # Verify state parameter to prevent CSRF
    expected_state = session.get("oidc_state")
    if not expected_state or state != expected_state:
        abort(403, "Invalid state parameter — possible CSRF attack")

    return _process_id_token(id_token)


def _process_id_token(id_token):
    """Validate and process an id_token, establishing a session."""
    # Decode the token
    # WARNING: In production, you MUST verify the JWT signature using
    # the IdP's public keys (JWKS). Use PyJWT or python-jose.
    claims = decode_id_token_unverified(id_token)

    # Validate claims including nonce
    is_valid, message = validate_id_token_claims(claims)
    if not is_valid:
        # Clean up session state
        session.pop("oidc_state", None)
        session.pop("oidc_nonce", None)
        abort(403, f"Token validation failed: {message}")

    # Clean up OIDC session state (single-use)
    session.pop("oidc_state", None)
    session.pop("oidc_nonce", None)

    # Establish user session
    session["user"] = {
        "sub": claims.get("sub"),
        "email": claims.get("email", ""),
        "name": claims.get("name", claims.get("preferred_username", "")),
        "groups": claims.get("groups", []),
    }
    session["id_token_raw"] = id_token

    # Redirect to the originally requested page or dashboard
    next_url = session.pop("next_url", url_for("dashboard"))
    return redirect(next_url)


